4.14 Advanced Topic: An Introduction to Digital Design Using a Hardware Design Language module RISCVCPU (clock);
parameter LW = 7'b000_0011, SW = 7'b010_0011, BEQ = 7'b110_0011, ALUop
= 7'b001_0011;
input clock;
reg [2:0] state;
wire [1:0] ALUOp, ALUSrcB;
wire [6:0] opcode;
wire MemtoReg, MemRead, MemWrite, IorD, RegWrite, IRWrite,
PCWrite, PCWriteCond, ALUSrcA, PCSource, MemoryOp;
// Create an instance of the RISC-V datapath, the inputs are the control signals; opcode is only output
Datapath RISCVDP (ALUOp, MemtoReg, MemRead, MemWrite, IorD, RegWrite,
IRWrite,
PCWrite, PCWriteCond, ALUSrcA, ALUSrcB, PCSource, opcode, clock);
initial begin state = 1; end // start the state machine in state 1
// These are the definitions of the control signals assign MemoryOp = (opcode == LW) || (opcode == SW); // a memory operation assign ALUOp = ((state == 1) || (state == 2) || ((state == 3) &&
MemoryOp)) ? 2'b00 : // add
((state == 3) && (opcode == BEQ)) ? 2'b01 : 2'b10; // subtract or use function code assign MemtoReg = ((state == 4) && (opcode == ALUop)) ? 0 : 1;
assign MemRead = (state == 1) || ((state == 4) && (opcode == LW));
assign MemWrite = (state == 4) && (opcode == SW);
assign IorD = (state == 1) ? 0 : 1;
assign RegWrite = (state == 5) || ((state == 4) && (opcode == ALUop));
assign IRWrite = (state == 1);
assign PCWrite = (state == 1);
assign PCWriteCond = (state == 3) && (opcode == BEQ);
assign ALUSrcA = ((state == 1) || (state == 2)) ? 0 : 1;
assign ALUSrcB = ((state == 1) || ((state == 3) && (opcode == BEQ))) ?
2'b01 :
(state == 2) ? 2'b11 :
((state == 3) && MemoryOp) ? 2'b10 : 2'b00; // memory operation or other assign PCSource = (state == 1) ? 0 : 1;
// Here is the state machine, which only has to sequence states always @(posedge clock) begin // all state updates on a positive clock edge case (state)
1: state <= 2; // unconditional next state
2: state <= 3; // unconditional next state
3: state <= (opcode == BEQ) ? 1 : 4; // branch go back else next state
4: state <= (opcode == LW) ? 5 : 1; // R-type and LW finish
5: state <= 1; // go back endcase end endmodule
