\\subsection{Advanced Material: Implementing Cache Controllers}

\\begin{verbatim}
//------------------------------------Cache FSM-------------------------
case(rstate)
/*idle state*/
idle : begin
/*If there is a CPU request, then compare cache tag*/
if (cpu_req.valid)
    vstate = compare_tag;
end
/*compare_tag state*/
compare_tag : begin
/*cache hit (tag match and cache entry is valid)*/
if (cpu_req.addr[TAGMSB:TAGLSB] == tag_read.tag && tag_read.valid) begin
    v_cpu_res.ready = '1;
    /*write hit*/
    if (cpu_req.rw) begin
        /*read/modify cache line*/
        tag_req.we = '1; data_req.we = '1;
        /*no change in tag*/
        tag_write.tag = tag_read.tag;
        tag_write.valid = '1;
        /*cache line is dirty*/
        tag_write.dirty = '1;
    end
    /*xaction is finished*/
    vstate = idle;
end
/*cache miss*/
else begin
    /*generate new tag*/
    tag_req.we = '1;
    tag_write.valid = '1;
    /*new tag*/
    tag_write.tag = cpu_req.addr[TAGMSB:TAGLSB];
    /*cache line is dirty if write*/
    tag_write.dirty = cpu_req.rw;
    /*generate memory request on miss*/
    v_mem_req.valid = '1;
    /*compulsory miss or miss with clean block*/
    if (tag_read.valid == 1'b0 || tag_read.dirty == 1'b0)
        /*wait till a new block is allocated*/
        vstate = allocate;
end
\\end{verbatim}

\\textbf{FIGURE e5.12.7} FSM in SystemVerilog, part III. Actual FSM states via case statement in this figure and the next. This figure has the Idle state and most of the Compare Tag state.

5.12 Advanced Material: Implementing Cache Controllers
480.e9 else begin
/*miss with dirty line*/
/*write back address*/ v_mem_req.addr = {tag_read.tag, cpu_req.addr[TAGLSB-1:0]};
v_mem_req.rw = ‘1;
/*wait till write is completed*/ vstate = write_back;
end end end
/*wait for allocating a new cache line*/ allocate: begin
/*memory controller has responded*/ if (mem_data.ready) begin
/*re-compare tag for write miss (need modify correct word)*/ vstate = compare_tag;
data_write = mem_data.data;
/*update cache line data*/ data_req.we = ‘1;
end end
/*wait for writing back dirty cache line*/ write_back : begin
/*write back is completed*/ if (mem_data.ready) begin
/*issue new memory request (allocating a new line)*/ v_mem_req.valid = ‘1;
v_mem_req.rw = ‘0;
vstate = allocate;
end end endcase end always_ff @(posedge(clk)) begin if (rst) rstate <= idle;
//reset to idle state else rstate <= vstate;
end
/*connect cache tag/data memory*/ dm_cache_tag ctag(.*);
dm_cache_data cdata(.*);
endmodule
