__global__ void csrmul_cached(unsigned int *Ap, unsigned int *Aj, float *Av, unsigned int num_rows, const float *x, float *y)
// Cache the rows of x[] corresponding to this block.
__shared__ float cache[blocksize];
unsigned int block_begin = blockIdx.x * blockDim.x;
unsigned int block_end = block_begin + blockDim.x;
unsigned int row = block_begin + threadIdx.x;
// Fetch and cache our window of x[].
if( row<num_rows) cache[threadIdx.x] = x[row];
__syncthreads();
if( row<num_rows ) unsigned int row_begin = Ap[row];
unsigned int row_end = Ap[row+1];
float sum = 0, x_j;
for(unsigned int col=row_begin; col<row_end; ++col) unsigned int j = Aj[col];
// Fetch x_j from our cache when possible if( j>=block_begin && j<block_end ) x_j = cache[j-block_begin];
else x_j = x[j];
sum += Av[col] * x_j;
y[row] = sum;
